"use strict";(globalThis.webpackChunkthe_python_ledger_engine=globalThis.webpackChunkthe_python_ledger_engine||[]).push([[378],{3910(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"category","label":"Foundations","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/Docusaurus-engine/foundations/introduction","label":"1. Introduction","docId":"foundations/introduction","unlisted":false},{"type":"link","href":"/Docusaurus-engine/foundations/programming-languages","label":"2. What is a programming language?","docId":"foundations/programming-languages","unlisted":false},{"type":"link","href":"/Docusaurus-engine/foundations/why-python","label":"3. What is Python","docId":"foundations/why-python","unlisted":false},{"type":"link","href":"/Docusaurus-engine/foundations/print-function","label":"4. The Print Function","docId":"foundations/print-function","unlisted":false},{"type":"link","href":"/Docusaurus-engine/foundations/variables","label":"5. Variables","docId":"foundations/variables","unlisted":false},{"type":"link","href":"/Docusaurus-engine/foundations/data-types","label":"6. Data Types","docId":"foundations/data-types","unlisted":false},{"type":"link","href":"/Docusaurus-engine/foundations/numbers-and-math","label":"7. Numbers and Math","docId":"foundations/numbers-and-math","unlisted":false},{"type":"link","href":"/Docusaurus-engine/foundations/comparisons","label":"8. Comparisons","docId":"foundations/comparisons","unlisted":false},{"type":"link","href":"/Docusaurus-engine/foundations/if-statements","label":"9. If Statements","docId":"foundations/if-statements","unlisted":false},{"type":"link","href":"/Docusaurus-engine/foundations/project-1-text-adventure","label":"\ud83c\udfc6 Project 1: Text Adventure","docId":"foundations/project-1-text-adventure","unlisted":false},{"type":"link","href":"/Docusaurus-engine/foundations/complex-data-types","label":"10. Complex data types","docId":"foundations/complex-data-types","unlisted":false},{"type":"link","href":"/Docusaurus-engine/foundations/loops","label":"11. Loops","docId":"foundations/loops","unlisted":false},{"type":"link","href":"/Docusaurus-engine/foundations/functions","label":"12. Functions","docId":"foundations/functions","unlisted":false}],"href":"/Docusaurus-engine/category/foundations"},{"type":"category","label":"Local development enviroment","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/Docusaurus-engine/local-development-enviroment/introduction","label":"introduction","docId":"local-development-enviroment/introduction","unlisted":false}],"href":"/Docusaurus-engine/category/local-development-enviroment"}]},"docs":{"foundations/comparisons":{"id":"foundations/comparisons","title":"Comparison Operators","description":"Programming isn\'t just about math; it\'s about making decisions. To make a decision, the computer needs to compare two values. The result of any comparison is always a Boolean (True or False).","sidebar":"tutorialSidebar"},"foundations/complex-data-types":{"id":"foundations/complex-data-types","title":"Complex data types","description":"Welcome to your next step in Python! While primitive data types (like integers, floats, and strings) hold a single value, Python has built-in complex data types that allow you to store, organize, and manipulate collections of data efficiently.","sidebar":"tutorialSidebar"},"foundations/data-types":{"id":"foundations/data-types","title":"Data Types","description":"Not all data is created equal. You can\'t multiply a \\"Name\\" by a \\"Phone Number,\\" and you can\'t capitalize a \\"Price.\\" To keep your code from crashing, you must understand the four fundamental Data Types in Python. These are also called primitive data types.","sidebar":"tutorialSidebar"},"foundations/functions":{"id":"foundations/functions","title":"Functions","description":"","sidebar":"tutorialSidebar"},"foundations/if-statements":{"id":"foundations/if-statements","title":"If Statements","description":"In a real-world ledger, you don\'t treat every entry the same way. If an account is overdrawn, you flag it. If a payment is massive, you verify it. In Python, we use Conditional Statements (if, elif, and else) to control the flow of our program.","sidebar":"tutorialSidebar"},"foundations/introduction":{"id":"foundations/introduction","title":"Welcome to the Ledger","description":"The Python Ledger is an open-source, community-driven roadmap designed to take you from writing your first line of code to building professional-grade software. We don\u2019t just teach you Python syntax; we teach you how to think like a developer.","sidebar":"tutorialSidebar"},"foundations/loops":{"id":"foundations/loops","title":"Loops","description":"Data is only useful if you can do something with it. In this lesson, we cover iteration\u2014the process of \\"looping\\" through a collection of data to perform an action on every item.","sidebar":"tutorialSidebar"},"foundations/numbers-and-math":{"id":"foundations/numbers-and-math","title":"Numbers and Math","description":"A ledger is useless if you can\'t add up the totals. In Python, we use Arithmetic Operators to perform calculations. Since you already know about Integers and Floats, let\'s see how they interact.","sidebar":"tutorialSidebar"},"foundations/print-function":{"id":"foundations/print-function","title":"The Print Function","description":"In the world of The Python Ledger, every action needs a record. To \\"speak\\" to the outside world, Python uses a built-in tool called a function. The most important one for a beginner is the print() function.","sidebar":"tutorialSidebar"},"foundations/programming-languages":{"id":"foundations/programming-languages","title":"What is a programming language?","description":"Think of a programming language as a bridge between humans and computers. Computers don\'t understand English or Spanish; they only understand electricity (on or off). A programming language allows us to write instructions in a way that humans can read, which then get translated into something the computer can execute.","sidebar":"tutorialSidebar"},"foundations/project-1-text-adventure":{"id":"foundations/project-1-text-adventure","title":"Project 1: The Ledger of Fate","description":"Congratulations! You have mastered the foundations of Python. You know how to:","sidebar":"tutorialSidebar"},"foundations/variables":{"id":"foundations/variables","title":"Variables","description":"In the previous lesson, we printed text directly. But what if you want to use the same piece of information ten times? Or what if that information changes?","sidebar":"tutorialSidebar"},"foundations/why-python":{"id":"foundations/why-python","title":"What is Python","description":"Python is a versatile, high-level programming language designed with a clear philosophy: code should be as easy to read as it is to write. Because its syntax closely mimics the English language, it removes the \\"language barrier\\" between your ideas and the computer, making it an ideal choice for beginners and professionals alike.","sidebar":"tutorialSidebar"},"local-development-enviroment/introduction":{"id":"local-development-enviroment/introduction","title":"introduction","description":"","sidebar":"tutorialSidebar"}}}}')}}]);